							signal axi_ms			: out axi_ms_r;
							signal axi_sm			: in axi_sm_r;
							signal clk				: in std_logic) is
	begin
		if OutputType_g = "AXIS" then
			CheckResultsAxiS(start, step, vld, rdy, last, data, clk);
		else
			CheckResultsAxiMM(start, step, axi_ms, axi_sm, clk);
		end if;
	end procedure;
